from rijndael.rijndael import Rijndael
import binascii

ciphertext = bytes.fromhex("")  # dán full chuỗi hex
key = bytes.fromhex("ecf2584110823e9d31c049207f8034b923f213b52c1ea9a2a18661dc6063a400")
iv = bytes.fromhex("91e94784686346258e6acc81009edd65")

block_size = 32  # 256-bit block

cipher = Rijndael(key, block_size)

plaintext = b''
prev = iv

for i in range(0, len(ciphertext), block_size):
    block = ciphertext[i:i+block_size]
    decrypted = cipher.decrypt(block)
    plaintext_block = bytes([a ^ b for a, b in zip(decrypted, prev)])
    plaintext += plaintext_block
    prev = block

print(plaintext)